let data = flow.get("icuData") || {};

let now = Date.now();

const SENSOR_TIMEOUT = 15000;

// =====================================
// REMOVE OLD VALUES
// =====================================

if (data.bpmTime && (now - data.bpmTime) > SENSOR_TIMEOUT) {
    delete data.bpm;
}

if (data.tempTime && (now - data.tempTime) > SENSOR_TIMEOUT) {
    delete data.temp;
}

if (data.spo2Time && (now - data.spo2Time) > SENSOR_TIMEOUT) {
    delete data.spo2;
}

if (data.roomTempTime && (now - data.roomTempTime) > SENSOR_TIMEOUT) {
    delete data.roomTemp;
}

if (data.humidityTime && (now - data.humidityTime) > SENSOR_TIMEOUT) {
    delete data.humidity;
}

if (data.pressureTime && (now - data.pressureTime) > SENSOR_TIMEOUT) {
    delete data.pressure;
}

flow.set("icuData", data);

// =====================================
// ALERT COOLDOWN
// =====================================

let lastAlertTime =
    flow.get("lastAlertTime") || 0;

if ((now - lastAlertTime) < 30000) {
    return null;
}

let alerts = [];

// BPM

if (data.bpm !== undefined) {
    if (data.bpm > 80) {
        alerts.push("High Heart Rate");
    }

    if (data.bpm > 0 && data.bpm < 50) {
        alerts.push("Low Heart Rate");
    }
}

// Body Temp

if (data.temp !== undefined) {
    if (data.temp > 30) {
        alerts.push("High Body Temperature");
    }
}

// SpO2

if (data.spo2 !== undefined) {
    if (data.spo2 > 0 && data.spo2 < 90) {
        alerts.push("Low SpO₂");
    }
}

// Room Temp

if (data.roomTemp !== undefined) {
    if (data.roomTemp > 35) {
        alerts.push("High Room Temperature");
    }
}

// Humidity

if (data.humidity !== undefined) {
    if (data.humidity > 80) {
        alerts.push("High Humidity");
    }
}

// Pressure

if (data.pressure !== undefined) {
    if (data.pressure < 950) {
        alerts.push("Low Pressure");
    }

    if (data.pressure > 1050) {
        alerts.push("High Pressure");
    }
}

if (alerts.length === 0) {
    return null;
}

flow.set("lastAlertTime", now);

msg.alerts = alerts;
msg.data = data;

return msg;

let d = msg.data;

let message = "🚨 ICU ALERT 🚨\n\n";

message += "Critical Conditions:\n";

for (let i = 0; i < msg.alerts.length; i++) {
    message += "• " + msg.alerts[i] + "\n";
}

message += "\n-----------------\n";
message += "Current Status\n";
message += "-----------------\n\n";

// Heart Rate

if (d.bpm !== undefined) {
    let status =
        (d.bpm > 80 || d.bpm < 50)
            ? "🔴 Critical"
            : "🟢 Normal";

    message +=
        "❤️ BPM: " +
        d.bpm +
        " (" +
        status +
        ")\n";
}

// Body Temp

if (d.temp !== undefined) {
    let status =
        d.temp > 30
            ? "🔴 Critical"
            : "🟢 Normal";

    message +=
        "🌡️ Body Temp: " +
        d.temp +
        "°C (" +
        status +
        ")\n";
}

// SpO2

if (d.spo2 !== undefined) {
    let status =
        d.spo2 < 90
            ? "🔴 Critical"
            : "🟢 Normal";

    message +=
        "🫁 SpO₂: " +
        d.spo2 +
        "% (" +
        status +
        ")\n";
}

// Room Temp

if (d.roomTemp !== undefined) {
    let status =
        d.roomTemp > 30
            ? "🔴 Critical"
            : "🟢 Normal";

    message +=
        "🏥 Room Temp: " +
        d.roomTemp +
        "°C (" +
        status +
        ")\n";
}

// Humidity

if (d.humidity !== undefined) {
    let status =
        d.humidity > 80
            ? "🔴 Critical"
            : "🟢 Normal";

    message +=
        "💧 Humidity: " +
        d.humidity +
        "% (" +
        status +
        ")\n";
}

// Pressure

if (d.pressure !== undefined) {
    let status =
        (d.pressure < 950 || d.pressure > 1050)
            ? "🔴 Critical"
            : "🟢 Normal";

    message +=
        "📈 Pressure: " +
        d.pressure +
        " hPa (" +
        status +
        ")\n";
}

msg.payload =
{
    chatId: 1334634124,
    type: "message",
    content: message
};

return msg;
